#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e6+5;
struct opt{int o,l,r,x,ans;}q[N];//操作
int n,m,a[N],sum0[N],B,tot;
int fa[N],t[N],max_,tag;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
inline int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
//找根节点的函数，并查集
inline void Merge(int u,int v){
    //u 连向 v（顺序不要反！）
    int fu=FF(u),fv=FF(v);
    if(fu!=fv)fa[fu]=fv;return;
}
inline void init(int l,int r){
    max_=0,tag=0;//清空
    for(int i=l;i<=r;i++)
        max_=max(max_,a[i]);//求出区间最大值
    for(int i=0;i<=max_;i++)
        t[i]=0,fa[i]=i;//初始化桶和并查集
    for(int i=l;i<=r;i++)t[a[i]]++;//处理桶
    return;
}
inline void sli(int l,int r){
    for(int i=l;i<=r;i++)
        a[i]=FF(a[i]);//确保每个都是正确的值
    return;
}
int main(){
    n=read(),m=read();//读入
    for(int i=1;i<=n;i++){
        a[i]=read();//读入
        sum0[i]=sum0[i-1]+(a[i]==0);
        //0 的前缀和，为查询 0 做准备
    }
    B=min(n,(int)(sqrt(n*3)));//取块长
    tot=(n+B-1)/B;//算出块的个数
    for(int i=1;i<=m;i++){
        q[i].o=read(),q[i].l=read();
        q[i].r=read(),q[i].x=read();//读入
        if(q[i].o==2&&q[i].x==0)//0 的查询
            q[i].ans=sum0[q[i].r]-sum0[q[i].l-1];
            //预处理好答案，之后就不用考虑啦
    }
    for(int k=1;k<=tot;k++){//k 表示当前块的编号
        int l=(k-1)*B+1,r=min(k*B,n);//求出该块覆盖范围
        init(l,r);//预处理这个块的基本信息
        for(int w=1;w<=m;w++){
            int o=q[w].o;
            int L=q[w].l,R=q[w].r;
            int val=q[w].x;
            //把需要用到的信息取出来方便使用
            if(o==2){//查询操作
                if(val==0)continue;//处理过了
                if(r<L||R<l)continue;//完全无交集
                if(val>max_-tag)continue;//显然不存在
                if(L<=l&&r<=R)q[w].ans+=t[val+tag];
                //整块则直接累加答案
                else{//否则是散块，暴力查
                    sli(l,r);//先把块拆了
                    for(int i=l;i<=r;i++){
                        if(i<L||i>R)continue;//不在区间内
                        if(a[i]-tag==val)q[w].ans++;//累加答案
                    }
                }
            }else{
                if(r<L||R<l)continue;//完全无交集
                if(max_-tag<=val)continue;//显然不会有变化
                if(!(L<=l&&r<=R)){//散块
                    sli(l,r);//散块都要拆块做
                    for(int i=l;i<=r;i++){
                        if(i<L||i>R)continue;//不在区间内
                        if(a[i]-tag>val)
                            t[a[i]]--,a[i]-=val,t[a[i]]++;
                            //更改值，并同步更新桶
                    }
                    for(int i=max_;i>=0;i--)
                        if(t[i]){max_=i;break;}
                        //有修改，实时维护区间最大值
                }else if(2*val<max_-tag){//真正修改的部分较多
                    //所以我们要转化把不用修改的地方加上然后整体减
                    for(int i=tag+1;i<=tag+val;i++){//枚举所有小的
                        t[i+val]+=t[i],t[i]=0;//更新桶
                        Merge(i,i+val);//并查集连边
                    }tag+=val;//累加标记
                }else{//真正修改的部分较少
                    //所以我们可以直接枚举需要修改的地方然后暴力修改
                    for(int i=tag+val+1;i<=max_;i++){
                        t[i-val]+=t[i],t[i]=0;//更新桶
                        Merge(i,i-val);//并查集连边
                    }
                    for(int i=max_;i>=0;i--)
                        if(t[i]){max_=i;break;}
                        //有修改，实时维护区间最大值
                }
            }
        }
    }
    for(int i=1;i<=m;i++)
        if(q[i].o==2)cout<<q[i].ans<<"\n";
    return 0;
}
